        <div className="flex flex-col p-6 sm:p-8 rounded-3xl bg-slate-900 border border-slate-700 shadow-2xl relative overflow-hidden">
          {/* Decorative background */}
          <div className="absolute top-[-30%] left-[-20%] w-[100%] h-[100%] bg-blue-500/10 blur-[100px] rounded-full pointer-events-none" />

          <div className="flex flex-col items-center gap-4 mb-4 relative z-10 text-center">
            {/* Big Profile Picture */}
            <div className="w-64 h-64 sm:w-72 sm:h-72 rounded-full bg-slate-800 border-[8px] border-slate-800 flex items-center justify-center text-8xl font-black text-slate-400 flex-shrink-0 shadow-[0_0_50px_-5px_rgba(0,0,0,0.6)] overflow-hidden relative">
              {player.imageUrl ? (
                <img
                  src={player.imageUrl}
                  alt={player.name}
                  className="w-full h-full object-cover"
                />
              ) : (
                player.name.slice(0, 2).toUpperCase()
              )}
            </div>

            {/* Main Info */}
            <div className="w-full px-2 mt-2">
              <h3 className="text-3xl sm:text-4xl font-heading font-bold text-white leading-tight mb-4 drop-shadow-md">
                {player.name}
              </h3>

              <div className="flex flex-col items-center gap-3">
                <div className="flex justify-center items-center gap-3">
                  <span className="text-sm font-black text-slate-500 tracking-widest w-8 text-right">
                    P1
                  </span>
                  <span
                    className={cn(
                      "text-xs sm:text-sm font-bold uppercase tracking-widest px-5 py-1.5 rounded-lg border min-w-[90px] text-center",
                      pos1Class,
                    )}
                  >
                    {pos1}
                  </span>
                </div>
                <div className="flex justify-center items-center gap-3">
                  <span className="text-sm font-black text-slate-500 tracking-widest w-8 text-right">
                    P2
                  </span>
                  <span
                    className={cn(
                      "text-xs sm:text-sm font-bold uppercase tracking-widest px-5 py-1.5 rounded-lg border min-w-[90px] text-center",
                      pos2Class ||
                        "text-slate-600 bg-slate-800/30 border-slate-700/50",
                    )}
                  >
                    {pos2 || "N/A"}
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Bottom Info Grid */}
          <div className="pt-5 border-t border-slate-800 w-full relative z-10 grid grid-cols-2 gap-6 bg-slate-900/50 -mx-6 sm:-mx-8 -mb-6 sm:-mb-8 px-6 sm:px-8 pb-6 sm:pb-8 rounded-b-3xl mt-6">
            {status === "SOLD" ? (
              <>
                <div>
                  <p className="text-[10px] text-slate-500 uppercase tracking-widest mb-1 font-bold">
                    Team
                  </p>
                  <p
                    className="font-bold text-xl text-slate-200"
                    title={player.team?.name}
                  >
                    {player.team?.name || player.team?.shortCode || "ΓÇö"}
                  </p>
                </div>
                <div>
                  <p className="text-[10px] text-slate-500 uppercase tracking-widest mb-1 font-bold">
