  const selectedTeamId = useAuctionStore((state) => state.selectedTeamId);
  const setBid = useAuctionStore((state) => state.setBid);

  const sellMutation = useSellPlayer();
  const nextMutation = useNextPlayer();

  useEffect(() => {
    if (currentBid === 0) {
