"use client";

import { useState } from "react";
import { getTeamLogoUrl } from "@/lib/brandfetch";

interface TeamLogoProps {
  domain: string;
  name: string;
  size?: number;
  className?: string;
}

export function TeamLogo({
  domain,
  name,
  size = 48,
  className = "",
}: TeamLogoProps) {
  const [errored, setErrored] = useState(false);
  const logoUrl = getTeamLogoUrl(domain, "icon", "light", size);

  const initial = name?.charAt(0).toUpperCase() ?? "?";

  return (
    <div
      className={`relative flex items-center justify-center shrink-0 overflow-hidden rounded-full ${className}`}
      style={{ width: size, height: size }}
    >
      {logoUrl && !errored ? (
        // Use plain <img> ΓÇö Brandfetch CDN URLs already deliver optimised WebP/PNG
        // and require the ?c= client-id param to be sent by the browser directly.
        // next/image proxies server-side and strips query-params, causing null responses.
        // eslint-disable-next-line @next/next/no-img-element
        <img
          src={logoUrl}
          alt={`${name} logo`}
          width={size}
          height={size}
          className="object-contain w-full h-full"
          onError={() => setErrored(true)}
        />
      ) : (
        <div
          className="w-full h-full bg-pitch-800 flex items-center justify-center text-xs font-bold text-slate-300 select-none"
          aria-label={`${name} logo placeholder`}
        >
          {initial}
        </div>
      )}
    </div>
  );
}

import { FIELD_MAPPING } from "./constants";
import type { ImportDraftRow, RawCsvRow } from "./types";

/** Trim a string; return null if blank. */
function toNullable(val: string | undefined): string | null {
  const trimmed = (val ?? "").trim();
  return trimmed === "" ? null : trimmed;
}

/** Trim a string; return empty string if blank. */
function toString(val: string | undefined): string {
  return (val ?? "").trim();
}

/**
 * Convert a raw CSV row into a structured ImportDraftRow.
 * Does NOT validate; just normalises field names and trims values.
 */
export function normalizeRow(raw: RawCsvRow, index: number): ImportDraftRow {
  const name = toString(raw[FIELD_MAPPING.NAME ?? "NAME"]);
  const year = toString(raw[FIELD_MAPPING.YEAR ?? "YEAR"]);
  const whatsappNumber = toString(
    raw[FIELD_MAPPING["Whatsapp Number"] ?? "Whatsapp Number"],
  );
  const stream = toString(raw[FIELD_MAPPING.STREAM ?? "STREAM"]);
  const position1 = toString(
    raw[FIELD_MAPPING["Primary Position"] ?? "Primary Position"],
  );
  const position2Raw = toNullable(
    raw[FIELD_MAPPING["Secondary Postion"] ?? "Secondary Postion"],
  );

  return {
    _key: `row-${index}`,
    name,
    year,
    whatsappNumber,
    stream,
    position1,
    position2: position2Raw,
    importOrder: index,
    errors: {},
    hasErrors: false,
  };
}

/**
 * Re-assign importOrder after rows are reordered or removed.
 */
export function reorderRows(rows: ImportDraftRow[]): ImportDraftRow[] {
  return rows.map((r, i) => ({ ...r, importOrder: i }));
}
